import base64,json,zlib
from pathlib import Path
ROOT=Path(__file__).resolve().parents[1]
DATA=ROOT/'android-learning'/'data'
PAYLOAD=''''''
lesson=json.loads(zlib.decompress(base64.b64decode(PAYLOAD)))
lesson_path=DATA/'lessons'/'d'/'d08.json'
lesson_path.parent.mkdir(parents=True,exist_ok=True)
lesson_path.write_text(json.dumps(lesson,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')
cat=json.loads((DATA/'catalog.json').read_text())
found=False
for chapter in cat['chapters']:
    for item in chapter['lessons']:
        if item['id']=='d08':
            assert item['status']=='planned'
            item['status']='published'; item['estimatedMinutes']=360; found=True
assert found
(DATA/'catalog.json').write_text(json.dumps(cat,ensure_ascii=False,indent=2)+'\n')
idx=json.loads((DATA/'search-index.json').read_text())
assert not any(x['lessonId']=='d08' for x in idx)
idx.append({'lessonId':'d08','code':'D08','title':'Modifier','keywords':['Modifier','Modifier.Node','LayoutModifier','DrawModifier','ParentDataModifier','constraints','measurement','placement','pointerInput','semantics','graphicsLayer','drawWithCache','clickable','offset','zIndex'],'headings':[s['title'] for s in lesson['sections']]})
(DATA/'search-index.json').write_text(json.dumps(idx,ensure_ascii=False,indent=2)+'\n')
plan=json.loads((DATA/'book-plan.json').read_text())
assert plan['current']=='d08' and 'd08' not in plan['completed']
plan['completed'].append('d08'); plan['current']='d09'
(DATA/'book-plan.json').write_text(json.dumps(plan,ensure_ascii=False,indent=2)+'\n')
expected=['objectives','prerequisites','terminology','mechanism','purpose','problem','when-to-use','when-not-to-use','requirement','analysis','minimal-code','upzi-case','alternatives','tradeoffs','edge-cases','mistakes','interview-basic','interview-deep','experience-answer','practice','scenario','checklist','summary','quiz-guide']
actual=[s['id'] for s in lesson['sections']]
assert actual==expected and len(set(actual))==24
quiz=[b for b in lesson['sections'][-1]['blocks'] if b['type']=='quiz'][0]['questions']
assert len(quiz)>=10
for q in quiz:
    ids={o['id'] for o in q['options']}; assert q['correctOptionIds'] and set(q['correctOptionIds'])<=ids and q['explanation'].strip()
text=json.dumps(lesson,ensure_ascii=False)
for label in ['confirmed','inferred','proposed','needs-confirmation']: assert label in text
paragraphs=sum(1 for s in lesson['sections'] for b in s['blocks'] if b['type']=='paragraph')
chars=sum(len(b['content']) for s in lesson['sections'] for b in s['blocks'] if b['type']=='paragraph')
codes=sum(1 for s in lesson['sections'] for b in s['blocks'] if b['type']=='code')
report={'id':'d08','sections':24,'uniqueSectionIds':24,'exactSectionOrder':True,'paragraphs':paragraphs,'paragraphCharacters':chars,'codeBlocks':codes,'quizQuestions':len(quiz),'quizAnswersValid':True,'truthfulnessLabelsPresent':True,'nextLesson':'d09'}
(ROOT/'validation-d08.json').write_text(json.dumps(report,ensure_ascii=False,indent=2)+'\n')
print(report)